        buf.extend_from_slice(&AF_UNIX.to_ne_bytes());
        match self {
            UnixSocketAddr::Unnamed => {}
            UnixSocketAddr::Abstract(name) => {
                buf.push(0);
                buf.extend_from_slice(name);
