use core::arch::global_asm;

use super::{task::VschedTaskImpl, trapframe::UserTrapFrame};

global_asm!(
    r#"
.globl vsched2_trap_vector
.align 4
vsched2_trap_vector:
    // ---- Phase 1: swap to pre-save stack ----
    //
    // sp  = buffer_top (never modified until .Lsave_context)
    // t3  = buffer_base = sp - KERNEL_STACK (used as trap frame base)
    //
    // All user regs except t3 are saved on stack at sp - offset
    // (negative offsets, within 12-bit range).
    csrrw   sp, sscratch, sp

    // Save user t0..t4 at buffer_top - offset (negative, 12-bit range ✓)
    sd      t0, -296(sp)
    sd      t1, -304(sp)
    sd      t2, -312(sp)
    sd      t3, -320(sp)
    sd      t4, -328(sp)

    // Save old sscratch (= buffer_top) to SAVED_SSCRATCH for trap_entry
    la      t0, {saved_sscratch_ptr}
    sd      sp, 0(t0)              // SAVED_SSCRATCH = buffer_top

    // t4 holds buffer_base for trap frame accesses
    li      t4, {kernel_stack_size}
    sub     t4, sp, t4             // t4 = buffer_base (sp unchanged!)

    // StarryOS design: kernel pages are mapped in all user page tables,
    // so kernel code/data/stack are accessible without SATP switch.

    // Set SUM and MXR
    li      t1, 0x40000
    csrs    sstatus, t1        // SUM (bit 18): allow S-mode load/store on U pages
    li      t1, 0x80000
    csrs    sstatus, t1        // MXR (bit 19): allow S-mode execute on U pages

    // ---- Phase 2: detect vsched2 into_kernel special ecall ----

    csrr    t0, scause
    li      t1, 8
    bne     t0, t1, .Lrestore_regs
    li      t1, 0xdead
    bne     a7, t1, .Lrestore_regs
    li      a0, 2
    csrr    t0, sstatus
    srli    a1, t0, 8
    andi    a1, a1, 1
    xori    a1, a1, 1
    call    vsched2_direct_entry_stub
    j       .

.Lrestore_regs:
    // ---- Phase 3: restore user t0..t3, save to trap frame ----
    // t4 = buffer_base (frame base), sp = buffer_top

    ld      t0, -296(sp)
    sd      t0, 40(t4)             // tf.regs.t0 = user t0
    ld      t1, -304(sp)
    sd      t1, 48(t4)             // tf.regs.t1 = user t1
    ld      t2, -312(sp)
    sd      t2, 56(t4)             // tf.regs.t2 = user t2
    ld      t3, -320(sp)           // t3 = user t3 (saved by .Lsave_context @224)

    // Save user sp (old sp is in sscratch after the swap)
    csrr    t0, sscratch
    sd      t0, 16(t4)

    // Restore sscratch to buffer_top (sp was never modified)
    csrw    sscratch, sp

.Lsave_context:
    // ---- Phase 4: save full trap context (t4 = frame base) ----

    csrr    t0, sepc
    csrr    t1, sstatus
    csrr    t2, scause
    sd      t0, 256(t4)
    sd      t1, 264(t4)
    sd      t2, 272(t4)
    csrr    t0, stval
    sd      t0, 280(t4)

    sd      zero, 0(t4)
    sd      ra, 8(t4)
    sd      gp, 24(t4)                // save user gp
    la      t0, {kernel_gp_ptr}        // restore kernel gp (per-CPU base)
    ld      gp, 0(t0)
    sd      tp, 32(t4)                // save user tp
    sd      s0, 64(t4)
    sd      s1, 72(t4)
    sd      a0, 80(t4)
    sd      a1, 88(t4)
    sd      a2, 96(t4)
    sd      a3, 104(t4)
    sd      a4, 112(t4)
    sd      a5, 120(t4)
    sd      a6, 128(t4)
    sd      a7, 136(t4)
    sd      s2, 144(t4)
    sd      s3, 152(t4)
    sd      s4, 160(t4)
    sd      s5, 168(t4)
    sd      s6, 176(t4)
    sd      s7, 184(t4)
    sd      s8, 192(t4)
    sd      s9, 200(t4)
    sd      s10, 208(t4)
    sd      s11, 216(t4)
    sd      t3, 224(t4)               // user t3 (restored in Phase 3)
    // Restore user t4 from stack, then save to frame
    ld      t3, -328(sp)              // t3 = user t4
    sd      t3, 232(t4)               // tf.regs.t4 = user t4
    sd      t5, 240(t4)
    sd      t6, 248(t4)

    li      t0, 1
    sd      t0, 288(t4)

    // call stub
    csrr    t0, scause
    srli    a0, t0, 63           // a0 = trap_type
    li      a1, 0                // a1 = privilege (kernel mode)
    mv      a2, t4               // a2 = &UserTrapFrame
    li      a3, 0                // a3 = no task_ptr
    call    vsched2_trap_entry_stub
    j       .

"#,
    kernel_gp_ptr = sym crate::vsched::KERNEL_GP,
    saved_sscratch_ptr = sym crate::vsched::SAVED_SSCRATCH,
    kernel_stack_size = const crate::vsched::KERNEL_STACK,
);

#[unsafe(no_mangle)]
extern "C" fn vsched2_direct_entry_stub(trap_type: usize, privilege: usize) -> ! {
    let entry = unsafe {
        libvsched2::VDSO_VTABLE.raw_trap_entry.expect("raw_trap_entry not in vtable")
    };
    unsafe {
        core::arch::asm!(
            "mv a0, {t}", "mv a1, {p}", "jalr {f}",
            t = in(reg) trap_type, p = in(reg) privilege, f = in(reg) entry,
            options(noreturn),
        );
    }
    unreachable!()
}

#[unsafe(no_mangle)]
extern "C" fn vsched2_trap_entry_stub(
    trap_type: usize, privilege: usize,
    tf_stack: *const UserTrapFrame, task_ptr: *const (),
) -> ! {
    let tf = unsafe { &*tf_stack };
    if tf.scause == 0x8000000000000005 {
        unsafe { core::arch::asm!("li {t}, -1", "csrw stimecmp, {t}", t = out(reg) _); }
    }

    static TRAP_COUNT: core::sync::atomic::AtomicUsize = core::sync::atomic::AtomicUsize::new(0);
    static mut TF_POOL: [UserTrapFrame; 4] = unsafe { core::mem::zeroed() };
    let trap_n = TRAP_COUNT.fetch_add(1, core::sync::atomic::Ordering::Relaxed);
    let idx = trap_n & 3;
    unsafe { core::ptr::copy_nonoverlapping(tf_stack, &raw mut TF_POOL[idx], 1) };
    let tf_ptr = unsafe { &raw mut TF_POOL[idx] as *mut UserTrapFrame };
// axlog::ax_println!(

    let mut task_ptr = task_ptr;
    if task_ptr.is_null() { task_ptr = libvsched2::current_task_ptr(); }
    if !task_ptr.is_null() {
        let vti = unsafe { &*(task_ptr as *const VschedTaskImpl) };
// axlog::ax_println!(
        vti.trap_frame.store(tf_ptr as usize, core::sync::atomic::Ordering::Release);
    }

    let entry = unsafe {
        libvsched2::VDSO_VTABLE.raw_trap_entry.expect("raw_trap_entry not in vtable")
    };
    let saved_sscratch = crate::vsched::SAVED_SSCRATCH.load(core::sync::atomic::Ordering::Acquire);
    unsafe {
        core::arch::asm!(
            "jalr {f}", f = in(reg) entry,
            in("a0") trap_type, in("a1") privilege, in("a2") saved_sscratch,
            options(noreturn),
        );
    }
    unreachable!()
}

// ---- OS yield entry ----

#[unsafe(no_mangle)]
#[unsafe(naked)]
unsafe extern "C" fn vsched_yield_trampoline() -> ! {
    core::arch::naked_asm!(
        "addi   sp, sp, -296",
        "sd     ra, 8(sp)",  "addi   t0, sp, 296", "sd     t0, 16(sp)",
        "sd     s0, 64(sp)",  "sd     s1, 72(sp)",
        "sd     s2, 144(sp)", "sd     s3, 152(sp)", "sd     s4, 160(sp)",
        "sd     s5, 168(sp)", "sd     s6, 176(sp)", "sd     s7, 184(sp)",
        "sd     s8, 192(sp)", "sd     s9, 200(sp)", "sd     s10, 208(sp)",
        "sd     s11, 216(sp)",
        // sepc = ra (return address, so task resumes after yield)
        "sd     ra, 256(sp)",
        // sstatus = current sstatus with SPP=1 so sret goes to S-mode
        "csrr   t0, sstatus", "ori    t0, t0, 0x100", "sd     t0, 264(sp)",
        // scause/stval = 0 (no trap), kind = 0 (Yield)
        "sd     zero, 272(sp)", "sd     zero, 280(sp)",
        "li     t0, 0", "sd     t0, 288(sp)",
        "mv     a0, sp", "call   vsched_yield_entry_stub",
    )
}

#[unsafe(no_mangle)]
extern "C" fn vsched_yield_entry_stub(tf_stack: *const UserTrapFrame) -> ! {
    let heap_tf = alloc::boxed::Box::new(unsafe { core::ptr::read(tf_stack) });
    let tf_ptr = alloc::boxed::Box::into_raw(heap_tf);

    let current_task = libvsched2::current_task_ptr();
    if !current_task.is_null() {
        let vti = unsafe { &*(current_task as *const VschedTaskImpl) };
// axlog::ax_println!(
        vti.trap_frame.store(tf_ptr as usize, core::sync::atomic::Ordering::Release);
    }

    let entry = unsafe {
        libvsched2::VDSO_VTABLE.raw_thread_entry.expect("raw_thread_entry not in vtable")
    };
    entry();
}

//! VschedStackImpl — vsched2 Stack 接口实现。
//!
//! 布局: [VschedStackImpl: 16B][buffer: KERNEL_STACK_SIZE bytes]
//!                                               ↑ base 指向 buffer 顶部(高地址)
//!
//! 栈从 buffer 顶部向下增长, 确保 Rust 函数序言 (addi sp,sp,-N)
//! 永远不会侵入 VSI 区域, 彻底避免了连续分配下的自覆盖问题。
//!
//! TODO: trap 向量入口的偏移量需要从正向(sp+offset)改为负向(sp-offset),
//!       因为 sscratch 现在指向 buffer 顶部而非底部。

use alloc::alloc::{Layout, alloc, dealloc};

use crate::config;

#[repr(C)]
pub struct VschedStackImpl {
    pub base: *mut (),
    pub magic: u64,
}

const VSI_MAGIC: u64 = 0xdeadbeefcafebabe;

fn stack_allocation_layout() -> (Layout, usize) {
    let vsi_layout = Layout::new::<VschedStackImpl>();
    let stack_layout = Layout::from_size_align(config::KERNEL_STACK_SIZE, 16)
        .expect("VschedStackImpl: invalid stack layout");
    vsi_layout
        .extend(stack_layout)
        .expect("VschedStackImpl: layout extend failed")
}

pub fn vsi_from_base(base: *mut ()) -> *mut VschedStackImpl {
    // base = buffer_top = ptr + sizeof(VSI) + KERNEL_STACK_SIZE
    // VSI = base - KERNEL_STACK_SIZE - sizeof(VSI)
    //     = base - (KERNEL_STACK_SIZE + vsi_layout.size())
    let vsi_layout = Layout::new::<VschedStackImpl>();
    let vsi_addr = (base as usize) - config::KERNEL_STACK_SIZE - vsi_layout.size();
    vsi_addr as *mut VschedStackImpl
}

impl libvsched2::Stack for VschedStackImpl {
    fn alloc() -> *mut () {
        let (total_layout, stack_offset) = stack_allocation_layout();
        let ptr = unsafe { alloc(total_layout) };
        assert!(!ptr.is_null(), "VschedStackImpl: failed to alloc");

        let self_ptr = ptr as *mut Self;
        // base points to the TOP of the buffer (high address), so stack grows
        // downwards AWAY from the VSI struct at the low end.
        let buffer_top = unsafe { ptr.add(stack_offset).add(config::KERNEL_STACK_SIZE) };
        unsafe {
            (*self_ptr).magic = VSI_MAGIC;
            (*self_ptr).base = buffer_top as *mut ();
        }
        axlog::ax_println!(
            "[stack::alloc] vsi={:#x} magic={:#x} base={:#x} (buffer_top) layout_size={}",
            self_ptr as usize, VSI_MAGIC, buffer_top as usize, total_layout.size(),
        );
        self_ptr as *mut ()
    }

    fn dealloc(&mut self) {
        let m = self.magic;
        let b = self.base;
        if m != VSI_MAGIC {
            axlog::ax_println!(
                "[stack::dealloc] CORRUPT! vsi={:#x} magic={:#x} (expected {:#x}) base={:#x}",
                self as *mut Self as usize, m, VSI_MAGIC, b as usize,
            );
        }
        let (total_layout, _) = stack_allocation_layout();
        let ptr = self as *mut Self as *mut u8;
        unsafe { dealloc(ptr, total_layout); }
    }

    fn base(&self) -> *mut () {
        let addr = self as *const Self as usize;
        let m = self.magic;
        let b = self.base;
        if m != VSI_MAGIC {
            axlog::ax_println!(
                "[stack::base] CORRUPT! this={:#x} magic={:#x} (expected {:#x}) base={:#x}",
                addr, m, VSI_MAGIC, b as usize,
            );
        } else {
            axlog::ax_println!("[stack::base] this={:#x} magic=OK base={:#x}", addr, b as usize);
        }
        b
    }

    fn from_base(base: *mut ()) -> *mut Self {
        let pre_save_base = crate::vsched::PRE_SAVE_BASE.load(core::sync::atomic::Ordering::Acquire);
        let pre_save_top = crate::vsched::PRE_SAVE_TOP.load(core::sync::atomic::Ordering::Acquire);
        if base.is_null()
            || base as usize == pre_save_base
            || base as usize == pre_save_top  // raw pre-save stack top (sscratch = stack_top)
        {
            axlog::ax_println!("[stack::from_base] base={:#x} SKIP (raw pre-save)", base as usize);
            return core::ptr::null_mut();
        }
        let vsi = vsi_from_base(base);
        unsafe {
            let m = (*vsi).magic;
            if m != VSI_MAGIC {
                axlog::ax_println!(
                    "[stack::from_base] CORRUPT! base={:#x} vsi={:#x} magic={:#x} (expected {:#x})",
                    base as usize, vsi as usize, m, VSI_MAGIC,
                );
            }
        }
        vsi
    }
}

//! VschedUserDataImpl — vsched2 UserData 接口实现。
//!
//! 5 步地址转换（根据 vsched2 接口注释实现）:
//!   1. 内核符号 → .so 内偏移:  offset = pos - kernel_vdso_start
//!   2. 用户 vDSO 基址:            user_vdso_base = get_process_vdso_base()
//!   3. 用户虚拟地址:              user_va = user_vdso_base + offset
//!   4. 查页表 → PA:               page_table.query(user_va) → pa
//!   5. PA → 内核 VA:              phys_to_virt(pa) + page_offset → kva
//!
//! Case 1 (vVAR): 内核/用户共享物理页，直接返回 pos（内核 VA）。
//!
//! vspace 参数语义（来自接口注释）:
//! - Some(kernel_ptr): 直接指向 AddrSpace 结构体（process_init 调用路径）
//! - Some(small_int):  CURRENT_VSPACE 填充的 PID 值
//! - None:             当前地址空间

use axhal::mem::phys_to_virt;
use axmm::AddrSpace;
use memory_addr::{PhysAddr, VirtAddr};

use super::{VSCHED2_VDSO_SIZE, VSCHED2_VDSO_START_PA, VSCHED2_VVAR_SIZE, VSCHED2_VVAR_START_PA, context::get_process_vdso_base};

pub struct VschedUserDataImpl;

impl libvsched2::UserData for VschedUserDataImpl {
    fn get_user_data(pos: usize, len: usize, vspace: Option<*mut ()>) -> *mut () {
        let end = match pos.checked_add(len) {
            Some(e) => e,
            None => return core::ptr::null_mut(),
        };

        // Case 1: vVAR — 内核和用户映射到同一物理页，直接返回 pos。
        {
            let vvar_start_pa = unsafe { VSCHED2_VVAR_START_PA };
            let vvar_size = unsafe { VSCHED2_VVAR_SIZE };
            let kernel_vvar_start = phys_to_virt(PhysAddr::from(vvar_start_pa)).as_usize();
            let kernel_vvar_end = kernel_vvar_start + vvar_size;

            if pos >= kernel_vvar_start && end <= kernel_vvar_end {
                return pos as *mut ();
            }
        }

        // Case 2: vDSO .data/.bss — per-process COW，5 步转换。
        {
            let vdso_start_pa = unsafe { VSCHED2_VDSO_START_PA };
            let vdso_size = unsafe { VSCHED2_VDSO_SIZE };
            let kernel_vdso_start = phys_to_virt(PhysAddr::from(vdso_start_pa)).as_usize();
            let kernel_vdso_end = kernel_vdso_start + vdso_size;

            if pos >= kernel_vdso_start && end <= kernel_vdso_end {
                // Step 1: offset within .so
                let offset = pos - kernel_vdso_start;

                // Step 2: user vDSO base — prefer per-AddrSpace, fall back to global
                const KERNEL_BASE: usize = 0xffffffc000000000;
                let user_vdso_base = match vspace {
                    Some(ptr) if ptr as usize >= KERNEL_BASE => {
                        let aspace = unsafe { &*(ptr as *const AddrSpace) };
                        aspace.vdso_base
                    }
                    _ => get_process_vdso_base(),
                };
                if user_vdso_base == 0 {
                    return core::ptr::null_mut();
                }

                // Step 3: user VA
                let user_va = user_vdso_base + offset;

                // Step 4-5: query page table → PA → kernel VA
                // (diagnostic logging suppressed for performance)
                if let Some(vspace_ptr) = vspace {
                    if vspace_ptr as usize >= KERNEL_BASE {
                        let user_page = user_va & !0xfff;
                        let page_offset = user_va & 0xfff;
                        let aspace = unsafe { &*(vspace_ptr as *const AddrSpace) };
                        if let Ok((pa, ..)) =
                            aspace.page_table().query(VirtAddr::from(user_page))
                        {
                            let kva = phys_to_virt(pa).as_usize() + page_offset;
                            return kva as *mut ();
                        }
                    }
                }

                // Fallback: return user VA.
                // (Valid when the target process's page table is active + SUM.)
                return user_va as *mut ();
            }
        }

        core::ptr::null_mut()
    }
}

