/// # 参数
///
/// - `config`: vdso构建配置结构体，详见[`BuildConfig`]。
pub fn build_vdso(config: &BuildConfig) {
    // // 用于打印环境变量的测试代码。
    // // 如果build_vdso执行失败，可能是主编译单元设置了某些环境变量，并被继承到了vdso的编译中。
    // let env = Command::new("env").output().unwrap();
